+                let value = parse_integer_expr(expr)?;
+                if value < 2 {
+                    return Err(FrankenError::OutOfRange {
+                        what: "fsqlite.mvcc_max_chain_length".into(),
+                        value: format!("{value} (minimum 2)"),
+                    });
+                }
+                #[allow(clippy::cast_sign_loss)]
+                {
